#include "perimortem/serialization/base64.hpp"

#include "validation/benchmark.hpp"

#include "perimortem/core/null_terminated.hpp"
#include "perimortem/core/perimortem.hpp"

using namespace Perimortem::Core;
using namespace Perimortem::Serialization;
using namespace Validation;

// 34-byte payload encoded as base64 (48 chars) — exercises the short path.
static constexpr auto base64_34 =
    "QmFzZTY0IHRlc3Qgc3RyaW5nIGZvciBQZXJpbW9ydGVtLg=="_view;

// A little over 1kb of text data generated by hand.
static constexpr auto base64_1kb =
    "QmFzZTY0IHRlc3Qgc3RyaW5nIGZvciBQZXJpbW9ydGVtLCiQgdGhpcyBpcyB0aGUgZXh0cm"
    "VtZWx5IGxvbmcgdmVyc2lvbiB3aGljaCBpcyByZXF1aXJlZCBpbiBvcmRlciBmb3IgdGhlIEFW"
    "WDIgb3B0aW1pemF0aW9uIHRvIGtpY2sgaW4uIElmIHlvdSBoYXZlIGFjdHVhbGx5IGRlY29kZW"
    "QgdGhpcyBzdHJpbmcgdG8gZmlndXJlIG91dCB3aGF0IHdhcyBpbiBpdCB0aGVuIEkgYW0gc2Fk"
    "IHRvIGluZm9ybSB5b3UgdGhhdCB0aGVyZSBpcyBub3RoaW5nIHJlYWxseSBvZiB2YWx1ZSBpbi"
    "B0aGlzIHRleHQuIEl0J3MganVzdCBhIHZlcnkgbG9uZyByYW1ibGluZyB0aGF0IGlzbid0IGFs"
    "bCBhIHNpbmdsZSBjaGFyYWN0ZXIgb3IgYSBzZXQgb2YgcmVwZWF0aW5nIHZhbHVlcyB0byBlbn"
    "N1cmUgd2UgYXJlIHRlc3RpbmcgbXVsdGlwbGUgZWRnZSBhbmQgYm91bmRzIGNvbmRpdGlvbnMu"
    "IFRoZSBiZXN0IHdheSB0byBnZXQgY292ZXJhZ2UgaXMgdG8gbWFrZSBzdXJlIHdlIGhhdmUgY2"
    "hhcmFjdGVycyBhbmQgb3RoZXIgZGF0YSBjb3ZlcmVkLiBBIHNtYXJ0ZXIgYXBwcm9hY2ggd291"
    "bGQgYmUgdG8gaW5jbHVkZSBiaW5hcnkgcGF5bG9hZHMgYXMgd2VsbCiQgd2UgY2FuIHNpbX"
    "BseSBpbmNsdWRlIGEgZmV3IGVtb2ppIGNoYXJhY3RlcnMgdG8gYmxvYXQgdGhlIGxlbmdodCBv"
    "ZiB0aGUgc3RyaW5nIGFzIHdlbGwgYXMgaW1wcm92ZSBjb3ZlcmFnZTog8J+ko/"
    "CfpKPwn6Sj8J+nkPCfkYzwn5GA8J+RgPCfkYDwn42V8J+PnfCfm6HihpXvuI/"
    "imIbimIXwn4en8J+Htw=="_view;

static constexpr Count batch_count = 1024;

static Harness Base64Bench = {
  .name = "Base64"_view,
};

PERIMORTEM_BENCHMARK(Base64Bench, decode_34_bytes) {
  Count size = 0;

  for (Count i = 0; i < batch_count; i++) {
    auto decoded = Base64::decode(base64_34);
    size += decoded.get_size();
  }

  Benchmark::prevent_optimization(size);
}

PERIMORTEM_BENCHMARK(Base64Bench, decode_1k_bytes) {
  Count size = 0;

  for (Count i = 0; i < batch_count; i++) {
    auto decoded = Base64::decode(base64_1kb);
    size += decoded.get_size();
  }

  Benchmark::prevent_optimization(size);
}
